import{G as e,c as t,b as i,ae as r}from"./chunks/framework.Cpb2nuHT.js";const m=JSON.parse('{"title":"事务","description":"","frontmatter":{"title":"事务","date":"2024-08-19T17:25:27.000Z","author":"花木凋零成兰","tags":["MySQL"],"cover":false,"hiddenCover":true},"headers":[],"relativePath":"Database/MySQL/事务.md","filePath":"Database/MySQL/事务.md","lastUpdated":1724079608000}'),o={name:"Database/MySQL/事务.md"};function l(n,a,d,h,s,c){return i(),t("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1724088327000"},[...a[0]||(a[0]=[r('<h1 id="事务" tabindex="-1">事务 <a class="header-anchor" href="#事务" aria-label="Permalink to &quot;事务&quot;">​</a></h1><p>一组逻辑操作单元, 使数据从一种状态变换为另一种状态;</p><h2 id="acid-特性" tabindex="-1">ACID 特性 <a class="header-anchor" href="#acid-特性" aria-label="Permalink to &quot;ACID 特性&quot;">​</a></h2><h3 id="原子性-atomicity" tabindex="-1">原子性(atomicity) <a class="header-anchor" href="#原子性-atomicity" aria-label="Permalink to &quot;原子性(atomicity)&quot;">​</a></h3><p>指事务是一个不可分割的工作单位, 要么全部提交, 要么全部失败回滚;</p><h3 id="一致性-consistency" tabindex="-1">一致性(consistency) <a class="header-anchor" href="#一致性-consistency" aria-label="Permalink to &quot;一致性(consistency)&quot;">​</a></h3><p>指事务执行前后, 数据从一个<strong>合法性状态</strong>到另一个<strong>合法性状态</strong>; 即<em>满足现实世界中的约束</em>, 比如银行账户余额一定要大于等于0;</p><h3 id="隔离性-isolation" tabindex="-1">隔离性(isolation) <a class="header-anchor" href="#隔离性-isolation" aria-label="Permalink to &quot;隔离性(isolation)&quot;">​</a></h3><p>指一个事务的执行不能被其他事务干扰, 即一个事务内部的操作及使用的数据对并发的其他事务是隔离的, 并发执行的各个事务之间不能互相干扰;</p><h3 id="持久性-durability" tabindex="-1">持久性(durability) <a class="header-anchor" href="#持久性-durability" aria-label="Permalink to &quot;持久性(durability)&quot;">​</a></h3><p>指一个事务一旦被提交, 对数据中数据的改变就是永久性的, 接下来的其他操作和数据库故障不该对其有任何影响;</p><p>持久性是通过事务日志来保证的, 日志包括了重做日志和回滚日志; 当对数据进行修改时, 首先会将数据库的变化信息记录到重做日志中, 然后再对数据库中对应的行进行修改; 如此即使数据库系统崩溃, 数据库重启后也能找到没有更新到数据库系统中的重做日志, 重新执行, 从而使事务具有持久性;</p><h3 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h3><p>原子性是基础, 隔离性是手段, 一致性是约束条件, 持久性是目的;</p><h2 id="事务状态" tabindex="-1">事务状态 <a class="header-anchor" href="#事务状态" aria-label="Permalink to &quot;事务状态&quot;">​</a></h2><h3 id="活动的-active" tabindex="-1">活动的(active) <a class="header-anchor" href="#活动的-active" aria-label="Permalink to &quot;活动的(active)&quot;">​</a></h3><p>事务对应的数据库操作正在执行过程中时, 事务处在 活动的 状态;</p><h3 id="部分提交的-partially-committed" tabindex="-1">部分提交的(partially committed) <a class="header-anchor" href="#部分提交的-partially-committed" aria-label="Permalink to &quot;部分提交的(partially committed)&quot;">​</a></h3><p>事务的最后一个操作执行完成, 由于操作都在内存中执行, 造成的影响并没有刷新到磁盘, 此时事务处在 部分提交的 状态;</p><h3 id="失败的-failed" tabindex="-1">失败的(failed) <a class="header-anchor" href="#失败的-failed" aria-label="Permalink to &quot;失败的(failed)&quot;">​</a></h3><p>当数据处在 活动的 或者 部分提交的 状态时, 可能遇到某些错误导致无法继续执行, 或者人为停止事务执行, 此时事务处在 失败的 状态;</p><h3 id="中止的-aborted" tabindex="-1">中止的(aborted) <a class="header-anchor" href="#中止的-aborted" aria-label="Permalink to &quot;中止的(aborted)&quot;">​</a></h3><p>如果事务执行一部分而变为失败的状态, 则需要把已经修改的事务中的操作还原到事务执行前的状态; 即撤销失败事务对当前数据库造成的影响, 这个撤销过程称之为 <strong>回滚</strong>;</p><p>回滚操作执行完毕后, 即数据库恢复到执行事务前的状态, 即事务处在 中止的 状态;</p><h3 id="提交的-committed" tabindex="-1">提交的(committed) <a class="header-anchor" href="#提交的-committed" aria-label="Permalink to &quot;提交的(committed)&quot;">​</a></h3><p>当事务处在 部分提交的 状态的事务将<strong>修改过的数据都同步到磁盘</strong>上, 就说事务处在了 提交的 状态;</p><h2 id="基本操作" tabindex="-1">基本操作 <a class="header-anchor" href="#基本操作" aria-label="Permalink to &quot;基本操作&quot;">​</a></h2><h3 id="基本步骤" tabindex="-1">基本步骤： <a class="header-anchor" href="#基本步骤" aria-label="Permalink to &quot;基本步骤：&quot;">​</a></h3><ol><li>开启事务</li><li>一系列操作</li><li>事务结束(提交、中止)</li></ol><h2 id="并发事务问题" tabindex="-1">并发事务问题 <a class="header-anchor" href="#并发事务问题" aria-label="Permalink to &quot;并发事务问题&quot;">​</a></h2><p>在 MySQL 同时处理多个事务的时候, 就可能会出现脏读、不可重复读、幻读的问题;</p><p>这三种问题的严重程度依次为：脏读 &gt; 不可重复读 &gt; 幻读;</p><h3 id="脏读" tabindex="-1">脏读 <a class="header-anchor" href="#脏读" aria-label="Permalink to &quot;脏读&quot;">​</a></h3><p>脏读是指假设事务 B 读取到了事务 A 未提交的数据, 若此时事务 A 回滚, 则事务 B 读取到的数据为过期数据;</p><h3 id="不可重复读" tabindex="-1">不可重复读 <a class="header-anchor" href="#不可重复读" aria-label="Permalink to &quot;不可重复读&quot;">​</a></h3><p>指在事务 A 内多次读取同一个数据, 此时同一个数据被另一个事务 B 修改并提交, 此时事务 A 再次读取同一个数据时, 发现前后两次读到的数据是不一致的;</p><h3 id="幻读" tabindex="-1">幻读 <a class="header-anchor" href="#幻读" aria-label="Permalink to &quot;幻读&quot;">​</a></h3><p>指一个事务 A 多次查询某个符合查询条件的 记录数量, 结果事务 B 在此时增加或删除了一条符合查询条件的记录数量, 则事务 A 再次查询符合条件的记录数量时, 前后不一致, 则发生了幻读;</p><h2 id="事务隔离级别" tabindex="-1">事务隔离级别 <a class="header-anchor" href="#事务隔离级别" aria-label="Permalink to &quot;事务隔离级别&quot;">​</a></h2><p>SQL标准一共有如下四种隔离级别来解决并发事务可能出现的三种问题(隔离级别从低到高, 性能从高到低)：</p><ol><li><strong>读未提交(read uncommitted)</strong>：指一个事务还没提交时, 对数据的修改能被其他事务看到; 此时可能会发生脏读、不可重复读、幻读现象;</li><li><strong>读提交(read committed)</strong>：指一个事务提交之后, 对数据的修改才能被其他事务看到; 此时可能会发生不可重复读、幻读现象;</li><li><strong>可重复读(repeatable read)</strong>：指一个事务执行过程中看到的数据, 与事务启动时看到的数据一致; 是MySQL InnoDB 引擎的默认隔离级别; 此时可能会发生幻读现象</li><li><strong>串行化(serializable)</strong>：对记录加读写锁, 当多个事务对记录进行读写操作时, 如果发生了读写冲突, 后访问的事务必须等前一个事务执行完成, 才能继续执行; 此时脏读、不可重复读、幻读均<strong>不可能</strong>会发生;</li></ol>',41)])])}const b=e(o,[["render",l]]);export{m as __pageData,b as default};
